  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "R2 has no route for 192.168.0.0/24; replies from 172.16.0.12 are forwarded toward R3 instead of back to R1, causing 192.168.0.12 to receive no replies.",
    "fix_summary": "Add a static route on R2 for 192.168.0.0/24 with next-hop 10.0.0.1 (R1) so return traffic is forwarded to R1.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "next_hop=10.0.0.1",
          "metric=1",
          "description=Return-route-to-192.168.0.0/24-via-R1"
        ]
      }
    ]
  }
}

